function VerifHierarquia(){
	var codGestor = hAPI.getCardValue('codGestor');
	var codDiretor = hAPI.getCardValue('codDiretor');
	var Solicitante = hAPI.getCardValue('cpLoginFluig');
	var retorno;
	
	if(codDiretor==Solicitante || codGestor==Solicitante){
		retorno=1;
	}else{
		retorno=3;
	}
	return retorno;
}

function Abertura(){

    var cpLoginFluig = hAPI.getCardValue('cpLoginFluig');
    var codGestorDestino = hAPI.getCardValue('codGestorDestino');
    var codGestorOrigem = hAPI.getCardValue('codGestorOrigem');
    var codDiretorOrigem = hAPI.getCardValue('codDiretorOrigem'); 
    
		if(cpLoginFluig!=codGestor &&  cpLoginFluig!=codDiretor!=""){
			retorno="GO";
			//passa gestor origem
		}
		if(cpLoginFluig==codGestor &&  cpLoginFluig!=codDiretor && codDiretor!=""){
			retorno="DO";
			//passa diretor origem
		}
		if(cpLoginFluig==codGestor &&  (cpLoginFluig==codDiretor || codDiretor=="") && CodNovaSecao!=""){
			retorno="GD";
			//passa gestor destino
		}
		if(cpLoginFluig==codGestor &&  (cpLoginFluig==codDiretor || codDiretor=="") && CodNovaSecao==""){
			retorno="RH";
			//passa RH
		}
}

function AprovaDiretor(){
	var Aprovacao = hAPI.getCardValue('cpAprovacaoDiretor');
	
	if(AprovacaoGestor=="1"){
		return true;
	}else{
		return false;
	}
}

function AprovaRH(){
	var Aprovacao = hAPI.getCardValue('cpAprovacaoRH');
	
	if(AprovacaoGestor=="1"){
		return true;
	}else{
		return false;
	}
}

function AprovaKit(){
	var Aprovacao = hAPI.getCardValue('cpAprovacaoKit');

	if(AprovacaoGestor=="1"){
		return true;
	}else{
		return false;
	}
}

function afterProcessCreate(processId) {
    // Grava o número do processo no formulário para referência futura
    hAPI.setCardValue("idProcessoFluig", processId);
    hAPI.setCardValue("cpNumeroSolicitacao", processId); 

    log.info(">>> ADMISSAO (AFTER PROCESS CREATE): Iniciando envio de E-mail de Boas Vindas. ID: " + processId);

    try {
        var nomeCandidato = hAPI.getCardValue("txtNomeColaborador");
        var emailRaw = hAPI.getCardValue("txtEmail");
        var emailCandidato = (emailRaw != null) ? String(emailRaw).trim() : "";
        
        // =========================================================================
        // ENVIO DO E-MAIL DE BOAS VINDAS COM O LINK DO PORTAL
        // =========================================================================
        var dataExame = hAPI.getCardValue("cpDataHoraExame");
        var localExame = hAPI.getCardValue("cpNomeClinica");
        var endExame = hAPI.getCardValue("cpEnderecoClinica");
        var assuntoEmail = hAPI.getCardValue("hidden_mail_assunto");
        var corpoEmail = hAPI.getCardValue("hidden_mail_corpo");

        if (corpoEmail == null || corpoEmail == "") {
            corpoEmail = "Olá! Seja bem-vindo(a). Por favor, acesse o portal para enviar seus documentos.";
        } else {
            corpoEmail = String(corpoEmail).replace(/\n/g, "<br>");
        }

        if (assuntoEmail == null || assuntoEmail == "") assuntoEmail = "Processo de Admissão - Monte Bravo";

        var baseUrl = getUrlConfiguracao("URL_PAGINA_CANDIDATO");
        var linkPortal = baseUrl + "?id_origem=" + processId;

        if (emailCandidato != null && emailCandidato != "") {
            var parametros = new java.util.HashMap();
            parametros.put("NOME_CANDIDATO", nomeCandidato);
            
            // Link para subir documentos no portal
            parametros.put("LINK_ADMISSAO", linkPortal); 
            
            parametros.put("DATA_EXAME", dataExame ? dataExame : "A ser agendado");
            parametros.put("LOCAL_EXAME", localExame ? localExame : "A ser informado");
            parametros.put("ENDERECO_EXAME", endExame ? endExame : "A ser informado");
            parametros.put("CORPO_PERSONALIZADO", corpoEmail);
            parametros.put("subject", assuntoEmail);
            parametros.put("SUBJECT", assuntoEmail);

            var destinatarios = new java.util.ArrayList();
            destinatarios.add(emailCandidato);
            
            notifier.notify("admin", "TPL_ADMISSAO_MASTER", parametros, destinatarios, "text/html");
            log.info(">>> ADMISSAO: E-mail enviado com sucesso para: " + emailCandidato);
        } else {
            log.warn(">>> ADMISSAO: E-mail do candidato está vazio. E-mail não enviado.");
        }

    } catch (e) {
        log.error(">>> ADMISSAO: ERRO NO AFTER PROCESS CREATE: " + e);
    }
}

/**
 * Função para buscar a URL base parametrizada no dataset de configurações
 */
function getUrlConfiguracao(campo) {
    try {
        var ds = DatasetFactory.getDataset("Form_Configuracoes_Admissao", null, [
            DatasetFactory.createConstraint("metadata#active", "true", "true", ConstraintType.MUST)
        ], null);
        if (ds && ds.rowsCount > 0) return ds.getValue(0, campo);
    } catch (e) { log.error("Erro config: " + e); }
    return "URL_NAO_CONFIGURADA";
}

function beforeTaskSave(colleagueId, nextSequenceId, userList) {
    var solicitacao = getValue("WKNumProces");
    var numState = getValue("WKNumState");
    
    log.info(">>> [ADMISSAO] beforeTaskSave executado na solicitação: " + solicitacao + " | Estado Atual: " + numState + " | Destino: " + nextSequenceId);

    // =========================================================================
    // AVISO DE ARQUITETURA
    // A geração de envelopes da TOTVS Assinatura Eletrônica (TAE) foi removida
    // do backend (servidor) para evitar falhas de transação no banco de dados.
    // Todo o fluxo de upload, envio de código e assinatura Headless acontece
    // agora exclusivamente no Front-end (Widget do Candidato).
    // =========================================================================
}

/**
 * Recupera os indices das linhas de um pai x filho.
 * 
 * @param fieldReference: id de um campo do pai x filho. Util para quando o formulario possui mais de um pai x filho.
 * @returns {java.util.TreeSet}: indice das linhas.
 */
function getIndexes(fieldReference){
	var regex = new RegExp(fieldReference+'___');
	var map = hAPI.getCardData(parseInt(getValue('WKNumProces')));
	var iterator = map.keySet().iterator();
	var indexes = new java.util.TreeSet();	

	while(iterator.hasNext()){
		var id = iterator.next();

		if(id.match(regex) == null) continue;
		else indexes.add(id.split('___')[1]);
	}

	return indexes;
}

function afterTaskSave(colleagueId, nextSequenceId, userList) {
    var atividadeAtual = getValue("WKNumState");
    var numSolicitacao = getValue("WKNumProces");

    log.info("### ADMISSAO DIGITAL [" + numSolicitacao + "]: Iniciando afterTaskSave. Atv Atual: " + atividadeAtual + " -> Destino: " + nextSequenceId);

    // =========================================================================
    // BLOCO 1: CONVERSÃO DE ANEXOS (Vindo da Página Pública ou Widget Assinatura)
    // =========================================================================
    var origem = hAPI.getCardValue("origem_dados");

    if (origem == "pagina_publica" || origem == "widget_saveAndSendTask") {
        log.info("### ADMISSAO DIGITAL: Origem pública detectada. Verificando anexos Base64.");

        // Lista de campos que podem conter arquivos Base64
        var docsParaProcessar = [
            ["cand_doc_rg_base64", "cand_doc_rg_nome"],
            ["cand_doc_titulo_base64", "cand_doc_titulo_nome"],
            ["cand_doc_escolaridade_base64", "cand_doc_escolaridade_nome"],
            ["cand_doc_residencia_base64", "cand_doc_residencia_nome"],
            ["cand_doc_banco_base64", "cand_doc_banco_nome"],
            ["cand_doc_nascimento_base64", "cand_doc_nascimento_nome"],
            ["cand_doc_cpf_base64", "cand_doc_cpf_nome"],
            ["cand_doc_reservista_base64", "cand_doc_reservista_nome"],
            ["cand_doc_cnh_base64", "cand_doc_cnh_nome"],
            ["cand_doc_ctps_base64", "cand_doc_ctps_nome"],
            ["cand_doc_pis_base64", "cand_doc_pis_nome"],
            ["cand_foto_base64", "cand_foto_nome"]
            // Nota: O comprovante de assinatura já vem via <attachments> no SOAP, 
            // então não precisa estar nesta lista se usar a widget nova corretamente.
        ];

        for (var i = 0; i < docsParaProcessar.length; i++) {
            var campoBase64 = docsParaProcessar[i][0];
            var campoNome = docsParaProcessar[i][1];

            try {
                processarAnexoBase64(campoBase64, campoNome);
            } catch (erroDoc) {
                log.error("### ADMISSAO DIGITAL: Erro ao anexar " + campoNome + ": " + erroDoc);
            }
        }

        // Limpa a flag para não processar novamente sem necessidade
        hAPI.setCardValue("origem_dados", "processado_fluig");
    }

    // =========================================================================
    // BLOCO 2: E-MAIL DE BOAS-VINDAS (Início do Processo)
    // =========================================================================
    if (atividadeAtual == 0 || atividadeAtual == 4 || atividadeAtual == 41) {
        var nomeColaborador = hAPI.getCardValue("txtNomeColaborador");
        var emailDestino = hAPI.getCardValue("txtEmail");

        if (emailDestino != null && emailDestino != "") {
            try {
                var parametros = new java.util.HashMap();
                parametros.put("NOME_CANDIDATO", nomeColaborador);
                parametros.put("NUM_SOLICITACAO", numSolicitacao);
                parametros.put("subject", "Confirmação de Recebimento - Solicitação " + numSolicitacao);

                var destinatarios = new java.util.ArrayList();
                destinatarios.add(emailDestino);

                notifier.notify("admin", "TPL_ADMISSAO_BOASVINDAS", parametros, destinatarios, "text/html");
            } catch (e) {
                log.warn("### ADMISSAO DIGITAL: Erro no envio de Boas Vindas: " + e);
            }
        }
    }

    // =========================================================================
    // BLOCO 3: E-MAIL DE CORREÇÃO (Saída do RH - Atv 97 -> Correção)
    // =========================================================================
    if (atividadeAtual == 97) {
        var decisaoRH = hAPI.getCardValue("cpAprovacaoAdmissao"); // 1=Aprovar, 2=Reprovar, 3=Corrigir

        if (decisaoRH == "3" || decisaoRH == "Corrigir") {
            try {
                enviarEmailCorrecao(numSolicitacao);
            } catch (e) {
                log.error("### ADMISSAO DIGITAL: Erro ao enviar e-mail de correção: " + e);
            }
        }
    }

    // =========================================================================
    // BLOCO 4: E-MAIL DE ASSINATURA DE CONTRATO (Saída do Kit - Atv 128 -> Assinatura)
    // =========================================================================
    if (atividadeAtual == 128) {
        var decisaoKitRaw = hAPI.getCardValue("cpAprovacaoKit");

        // 1. Blindagem contra nulo e padronização (Tudo maiúsculo e sem espaços)
        var decisaoKit = (decisaoKitRaw != null) ? String(decisaoKitRaw).toUpperCase().trim() : "";

        // LOG PARA DEBUG: Vai imprimir no server.log EXATAMENTE o que o Fluig está lendo
        log.info("### ADMISSAO [ASSINATURA]: Atv 128 salva. Valor do cpAprovacaoKit lido: [" + decisaoKit + "]");

        // 2. Abordagem ampla: aceita as variações comuns de aprovação
        if (decisaoKit == "1" || decisaoKit == "APROVADO" || decisaoKit == "APROVAR" || decisaoKit == "SIM") {
            log.info("### ADMISSAO [ASSINATURA]: Condição validada! Chamando enviarEmailAssinatura()...");
            try {
                enviarEmailAssinatura(numSolicitacao);
            } catch (e) {
                log.error("### ADMISSAO [ASSINATURA]: ERRO Fatal ao tentar enviar e-mail: " + e);
            }
        } else {
            log.warn("### ADMISSAO [ASSINATURA]: A decisão foi [" + decisaoKit + "]. Como não é Aprovar, o e-mail não será enviado.");
        }
    }

    // =========================================================================
    // BLOCO 5: DOCUMENTOS DO CANDIDATO (Ao sair da Admissão RH 97 -> 138)
    // =========================================================================
    if (atividadeAtual == 97) {
        var pastaCandidato = hAPI.getCardValue("cpIdPastaDocsCandidato");
        moverAnexosParaSubpasta(pastaCandidato, numSolicitacao, atividadeAtual);
    }

    // =========================================================================
    // BLOCO 6: DOCUMENTOS GERADOS DO KIT (Ao sair da Validação 128 -> 129)
    // =========================================================================
    if (atividadeAtual == 128) {
        var pastaKit = hAPI.getCardValue("cpIdPastaDocsGerados");
        moverAnexosParaSubpasta(pastaKit, numSolicitacao, atividadeAtual);
    }

    // =========================================================================
    // BLOCO 7: DOCUMENTOS ASSINADOS (Ao sair da Assinatura 129 -> 104)
    // =========================================================================
    if (atividadeAtual == 129) {
        var pastaAssinados = hAPI.getCardValue("cpIdPastaDocsAssinados");
        moverAnexosParaSubpasta(pastaAssinados, numSolicitacao, atividadeAtual);
    }

}

// =============================================================================
// FUNÇÕES AUXILIARES (FORA DO ESCOPO DA afterTaskSave)
// =============================================================================

// Esta função envia um e-mail para o candidato com um link direto para a Widget Pública de Assinatura. O link é personalizado com o número da solicitação para facilitar a navegação do usuário.
function enviarEmailAssinatura(numSolicitacao) {
    var nome = hAPI.getCardValue("txtNomeColaborador");
    var emailRaw = hAPI.getCardValue("txtEmail");

    if (emailRaw != null && emailRaw != "") {
        // Limpa espaços vazios invisíveis que causam o erro "Invalid Addresses"
        var email = String(emailRaw).trim();

        // URL da Widget Pública de Assinatura
        var urlBase = getUrlConfiguracao("URL_PAGINA_ASSINATURA");
        var linkAssinatura = urlBase + "?id_origem=" + numSolicitacao;

        var parametros = new java.util.HashMap();
        parametros.put("NOME_CANDIDATO", nome);
        parametros.put("LINK_ASSINATURA", linkAssinatura);
        parametros.put("LINK_ADMISSAO", linkAssinatura);

        var corpoMsg = "Parabéns! Sua admissão foi aprovada e seu contrato gerado com sucesso.<br/><br/>" +
            "O último passo é realizar a <b>Assinatura Digital</b> dos seus documentos.<br/>" +
            "Acesse o portal de forma segura clicando no botão abaixo.";

        parametros.put("CORPO_PERSONALIZADO", corpoMsg);

        parametros.put("subject", "Ação Necessária - Assinatura de Contrato");
        parametros.put("SUBJECT", "Ação Necessária - Assinatura de Contrato");

        var dest = new java.util.ArrayList();
        // Usamos a variável limpa diretamente
        dest.add(email);

        notifier.notify("admin", "TPL_ADMISSAO_CANDIDATO_REDUZIDO", parametros, dest, "text/html");

        log.info("### ADMISSAO DIGITAL: Convite de assinatura inserido na fila para " + email);
    } else {
        log.warn("### ADMISSAO DIGITAL: E-mail não preenchido. Convite de assinatura cancelado.");
    }
}

// Esta função envia um e-mail para o candidato solicitando correção de dados, com um link direto para a Widget Pública de Correção. O motivo da correção é destacado no corpo do e-mail.
function enviarEmailCorrecao(numSolicitacao) {
    var nome = hAPI.getCardValue("txtNomeColaborador");
    var email = hAPI.getCardValue("txtEmail");
    var parecerRH = hAPI.getCardValue("cpParecerAprovaAdmissao");

    if (email != null && email != "") {
        // Link da Widget Pública de Correção
        var urlBase = getUrlConfiguracao("URL_PAGINA_CORRECAO");
        var linkCorrecao = urlBase + "?id_origem=" + numSolicitacao;

        var parametros = new java.util.HashMap();
        parametros.put("NOME_CANDIDATO", nome);
        parametros.put("LINK_ADMISSAO", linkCorrecao);

        var corpoMsg = "<b>O RH solicitou uma correção nos seus documentos:</b><br/><br/>" +
            "<div style='background-color:#fff3cd; color:#856404; padding:15px; border-left:5px solid #ffc107;'>" +
            "<b>Motivo:</b> " + (parecerRH ? parecerRH : "Verifique os dados cadastrais.") +
            "</div><br/>" +
            "Clique no botão abaixo para acessar o formulário e corrigir.";

        parametros.put("CORPO_PERSONALIZADO", corpoMsg);
        parametros.put("subject", "Ação Necessária - Correção de Dados");

        var dest = new java.util.ArrayList();
        dest.add(email);

        notifier.notify("admin", "TPL_ADMISSAO_CANDIDATO_REDUZIDO", parametros, dest, "text/html");
    }
}

// Esta função processa um campo Base64, cria um arquivo temporário, publica no GED e anexa à solicitação. Depois tenta apagar o arquivo temporário de forma segura.
function processarAnexoBase64(campoBase64, campoNomeArquivo) {
    var base64 = hAPI.getCardValue(campoBase64);
    var nomeArquivo = hAPI.getCardValue(campoNomeArquivo);

    if (base64 != null && base64 != "" && nomeArquivo != null && nomeArquivo != "") {
        // Remove cabeçalho data:image/png;base64, se existir
        if (base64.indexOf(",") > -1) {
            base64 = base64.split(",")[1];
        }

        try {
            // 1. Decodifica o Base64
            var decodedBytes = javax.xml.bind.DatatypeConverter.parseBase64Binary(base64);

            // 2. Cria um arquivo físico na pasta temporária do servidor Fluig
            var tempDir = java.lang.System.getProperty("java.io.tmpdir");
            var tempFile = new java.io.File(tempDir + java.io.File.separator + nomeArquivo);
            var fos = new java.io.FileOutputStream(tempFile);
            fos.write(decodedBytes);
            fos.flush();
            fos.close();

            // Substitua as linhas do idPastaDestino por isto:
            var pastaDocsCand = hAPI.getCardValue("cpIdPastaDocsCandidato");
            var idPastaDestino = (pastaDocsCand != null && pastaDocsCand != "") ? parseInt(pastaDocsCand) : parseInt(hAPI.getCardValue("cpIdPastaGedCandidato"));

            var dto = fluigAPI.getDocumentService().buildDocumentVO();
            dto.setDocumentDescription(nomeArquivo);
            dto.setParentDocumentId(idPastaDestino);
            dto.setPhisicalFile(tempFile.getAbsolutePath());

            var docVO = fluigAPI.getDocumentService().createDocument(dto, "", false);
            var idDocumentoGED = docVO.getDocumentId();

            // 4. Anexa o documento efetivamente à solicitação Workflow
            hAPI.attachDocument(idDocumentoGED);

            // 5. Atualiza o campo base64 no formulário
            hAPI.setCardValue(campoBase64, "[ANEXADO]");

            // 6. Tenta apagar o arquivo temporário de forma segura
            try {
                // Força o Java a apagar quando a rotina terminar, caso esteja em uso
                tempFile.deleteOnExit();

                // Tenta apagar imediatamente usando a classe NIO do Java (mais segura que o .delete comum)
                var path = java.nio.file.Paths.get(tempFile.getAbsolutePath());
                java.nio.file.Files.deleteIfExists(path);

            } catch (erroDelete) {
                log.warn("### ADMISSAO DIGITAL: Não foi possível apagar o arquivo temporário agora. Ele será limpo pelo sistema depois. Arquivo: " + tempFile.getAbsolutePath());
            }
            hAPI.setCardValue(campoBase64, "[ANEXADO]");

        } catch (e) {
            throw "Falha na conversão e anexo do Base64 (" + nomeArquivo + "): " + e;
        }
    }
}

function getUrlConfiguracao(campo) {
    try {
        var ds = DatasetFactory.getDataset("Form_Configuracoes_Admissao", null, [
            DatasetFactory.createConstraint("metadata#active", "true", "true", ConstraintType.MUST)
        ], null);
        if (ds && ds.rowsCount > 0) {
            return ds.getValue(0, campo);
        }
    } catch (e) { log.error("Erro ao ler Form_Configuracoes_Admissao: " + e); }
    return "URL_NAO_CONFIGURADA";
}

// Função auxiliar para mover os anexos soltos para a respectiva subpasta
function moverAnexosParaSubpasta(idPastaDestino, numSolicitacao, atividadeAtual) {
    if (idPastaDestino == null || idPastaDestino.trim() == "") {
        log.warn("### ADMISSAO DIGITAL ALERTA [" + numSolicitacao + "]: ID da subpasta destino não encontrado.");
        return;
    }

    // NOVA CONSULTA: Lê a atividade de assinatura configurada globalmente
    var atvAssinatura = 129;
    try {
        var dsConfig = DatasetFactory.getDataset("Form_Configuracoes_Admissao", null, [
            DatasetFactory.createConstraint("metadata#active", "true", "true", ConstraintType.MUST)
        ], null);
        if (dsConfig && dsConfig.rowsCount > 0) {
            var confAssinatura = dsConfig.getValue(0, "ATIVIDADE_CANDIDATO_ASSINATURA");
            if (confAssinatura != null && confAssinatura != "") {
                atvAssinatura = parseInt(confAssinatura);
            }
        }
    } catch (e) { log.error("Erro ao buscar config da atv de assinatura: " + e); }

    try {
        var codigoPasta = java.lang.Integer.valueOf(idPastaDestino.trim());
        var dataAtual = java.util.Calendar.getInstance().getTime();
        var docs = hAPI.listAttachments();

        // Mapeia onde estão as nossas 4 gavetas de organização (incluindo a raiz)
        var idPastaPrincipal = parseInt(hAPI.getCardValue("cpIdPastaGedCandidato") || "0");
        var idSub1 = parseInt(hAPI.getCardValue("cpIdPastaDocsCandidato") || "0");
        var idSub2 = parseInt(hAPI.getCardValue("cpIdPastaDocsGerados") || "0");
        var idSub3 = parseInt(hAPI.getCardValue("cpIdPastaDocsAssinados") || "0");

        if (docs != null && docs.size() > 0) {
            for (var i = 0; i < docs.size(); i++) {
                var doc = docs.get(i);
                if (doc == null) continue;

                var parentId = doc.getParentDocumentId();
                var nomeAnexo = String(doc.getDocumentDescription());
                var tipoAnexo = String(doc.getDocumentType());

                // ==========================================================
                // REGRA DE OURO V3: Protege as pastas, com exceções controladas
                // ==========================================================
                if (parentId == idSub1 || parentId == idSub2 || parentId == idSub3 || parentId == idPastaPrincipal) {

                    // Exceção 1: Na Assinatura (129), permite puxar os "Assinados" para a Subpasta 3
                    if (atividadeAtual == 129 && nomeAnexo.indexOf("Assinado") > -1 && parentId != idSub3) {
                        // Deixa passar
                    }
                    // Exceção 2: Na Admissão RH (97), permite organizar o que estiver solto na Raiz para a Subpasta 1
                    else if (atividadeAtual == 97 && parentId == idPastaPrincipal) {
                        // Deixa passar
                    }
                    else {
                        continue; // Está seguro na estrutura, pula para o próximo!
                    }
                }

                // Efetua a movimentação do arquivo solto para a gaveta certa
                if (tipoAnexo == "2" || tipoAnexo == "7" || tipoAnexo == "1") {
                    doc.setParentDocumentId(codigoPasta);
                    doc.setExpires(false);
                    doc.setCreateDate(dataAtual);
                    doc.setInheritSecurity(true);
                    doc.setTopicId(1);
                    doc.setUserNotify(false);
                    doc.setValidationStartDate(dataAtual);
                    doc.setVersionOption("0");
                    doc.setUpdateIsoProperties(true);

                    hAPI.publishWorkflowAttachment(doc);
                    log.info("### ADMISSAO DIGITAL [" + numSolicitacao + "]: Arquivo '" + nomeAnexo + "' organizado na pasta " + codigoPasta);
                }
            }
        }
    } catch (e) {
        log.error("### ADMISSAO DIGITAL ERRO AO ORGANIZAR ANEXOS [" + numSolicitacao + "]: " + e);
    }
}

/**
 * Função auxiliar para buscar a URL parametrizada no dataset de configurações
 */
function getUrlConfiguracao(campo) {
    try {
        var ds = DatasetFactory.getDataset("Form_Configuracoes_Admissao", null, [
            DatasetFactory.createConstraint("metadata#active", "true", "true", ConstraintType.MUST)
        ], null);
        if (ds && ds.rowsCount > 0) return ds.getValue(0, campo);
    } catch (e) { log.error("Erro config URL: " + e); }
    return "URL_NAO_CONFIGURADA";
}

function servicetask139(attempt, message) {
    log.info("### Admissão SOAP RM (Campos Complementares e Emergência) - INICIO ###");

    try {
        // =========================================================================
        // 1. FUNÇÕES AUXILIARES DE FORMATAÇÃO E LEITURA
        // =========================================================================
        var getStr = function (name) {
            var v = hAPI.getCardValue(name);
            if (v == null || v == undefined) return "";
            return String(v).trim();
        };

        function tag(n, v) {
            if (v === null || v === undefined || String(v).trim() === "") return "";
            return "<" + n + ">" + escapeXML(v) + "</" + n + ">";
        }

        function escapeXML(str) {
            return String(str || "").replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
        }

        // =========================================================================
        // 2. CONFIGURAÇÕES DO WEBSERVICE (VIA DATASET SECURIZADO)
        // =========================================================================
        var dsConfig = DatasetFactory.getDataset("Form_Configuracoes_Admissao", null, [
            DatasetFactory.createConstraint("metadata#active", "true", "true", ConstraintType.MUST)
        ], null);

        if (!dsConfig || dsConfig.rowsCount === 0) {
            throw "ERRO FATAL: Configurações de Integração não encontradas no dataset Form_Configuracoes_Admissao.";
        }

        var NOME_SERVICO_FLUIG = "WSDATASERVER";
        var SISTEMA = "P";
        var RM_USER = dsConfig.getValue(0, "RM_USER");
        var RM_PASS = dsConfig.getValue(0, "RM_PASS");
        var ENDPOINT_URL = dsConfig.getValue(0, "RM_ENDPOINT_WS");

        // =========================================================================
        // 3. EXTRAÇÃO DAS CHAVES E CAMPOS COMPLEMENTARES
        // =========================================================================
        // Captura as chaves primárias geradas na task 138
        var COLIGADA = getStr("FUN_EMPRESA");
        var CHAPA = getStr("FUN_CHAPA") || getStr("TxtChapa");
        var CODPESSOA = getStr("FUN_CODPESSOA") || getStr("txtCodigoPeExist");

        if (!COLIGADA || COLIGADA === "") throw "Coligada não informada.";
        if (!CHAPA || CHAPA === "") throw "Chapa não informada. A integração principal (138) falhou ou não gerou a chapa.";
        if (!CODPESSOA || CODPESSOA === "") throw "Código da Pessoa (CODPESSOA) não foi gravado pela etapa 138. É obrigatório para atualizar a tabela de emergência (VPCOMPL).";

        var RM_CONTEXTO = "CODCOLIGADA=" + COLIGADA + ";CODSISTEMA=" + SISTEMA + ";CODUSUARIO=" + RM_USER;

        var tamanhoCamisa = getStr("txtTamanhoCamisa");
        var tamanhoCalcado = getStr("txtTamanhoCalcado");
        
        var nomeEmergencia = getStr("txtNomeEmergencia");
        var parentescoEmergencia = getStr("txtParentescoEmergencia");
        var telefoneEmergencia = getStr("txtTelefoneEmergencia");

        // Se todos os campos estiverem vazios, não há necessidade de chamar o RM
        if (tamanhoCamisa === "" && tamanhoCalcado === "" && nomeEmergencia === "" && parentescoEmergencia === "" && telefoneEmergencia === "") {
            log.info("### NENHUM DADO COMPLEMENTAR PARA INTEGRAR. IGNORANDO TASK 139...");
            return true;
        }

        // =========================================================================
        // 4. MONTAGEM DE INTEGRAÇÃO DO XML (PFCOMPL E VPCOMPL SEPARADAS)
        // =========================================================================
        var xmlCompl = "";
        xmlCompl += "<FopFunc>\n";
        
        // A tag PFunc é enviada apenas com as chaves para que o RM saiba qual funcionário atualizar
        xmlCompl += "  <PFunc>\n";
        xmlCompl += tag("CODCOLIGADA", COLIGADA);
        xmlCompl += tag("CHAPA", CHAPA);
        xmlCompl += "  </PFunc>\n";

        // Tabela PFCOMPL (Tamanhos e Fardamento) - Ligação por Coligada e Chapa
        if (tamanhoCamisa !== "" || tamanhoCalcado !== "") {
            xmlCompl += "  <PFCOMPL>\n";
            xmlCompl += tag("CODCOLIGADA", COLIGADA);
            xmlCompl += tag("CHAPA", CHAPA);
            
            if (tamanhoCamisa !== "") xmlCompl += tag("TAMANHO_CAMISA", tamanhoCamisa);
            if (tamanhoCalcado !== "") xmlCompl += tag("CALCADO", tamanhoCalcado);
            
            xmlCompl += "  </PFCOMPL>\n";
        }

        // // Tabela VPCOMPL (Emergência) - Ligação EXCLUSIVA por CODPESSOA (conforme documentação do RM)
        // if (nomeEmergencia !== "" || parentescoEmergencia !== "" || telefoneEmergencia !== "") {
        //     xmlCompl += "  <VPCOMPL>\n";
        //     xmlCompl += tag("CODPESSOA", CODPESSOA); 
            
        //     if (nomeEmergencia !== "") xmlCompl += tag("CONTATO_EMERGENCIA", nomeEmergencia);
        //     if (parentescoEmergencia !== "") xmlCompl += tag("GRAU_PAR_EMER", parentescoEmergencia);
        //     if (telefoneEmergencia !== "") xmlCompl += tag("TELEFONE_EMERGENCIA", telefoneEmergencia);
            
        //     xmlCompl += "  </VPCOMPL>\n";
        // }

        xmlCompl += "</FopFunc>";

        log.info("### XML DE INTEGRAÇÃO MONTADO (COMPLEMENTARES): \n" + xmlCompl);

        // =========================================================================
        // 5. CONSUMO DO WEBSERVICE SOAP DO RM
        // =========================================================================
        var serviceProvider = ServiceManager.getService(NOME_SERVICO_FLUIG);
        var serviceLocator = serviceProvider.instantiate("com.totvs.WsDataServer");
        var authService = serviceLocator.getRMIwsDataServer();

        var client = authService;
        var bindingProvider = client;
        var requestContext = bindingProvider.getRequestContext();
        requestContext.put("javax.xml.ws.security.auth.username", RM_USER);
        requestContext.put("javax.xml.ws.security.auth.password", RM_PASS);

        try {
            requestContext.put("javax.xml.ws.service.endpoint.address", ENDPOINT_URL);
        } catch (e) {
            log.warn("Aviso Endpoint RM: " + e);
        }

        // Executa a gravação. O RM fará o UPDATE nas tabelas correspondentes.
        var result = authService.saveRecord("FopFuncData", xmlCompl, RM_CONTEXTO);
        log.info("### RETORNO RM (COMPLEMENTARES): " + result);

        if (result && result.indexOf("===") != -1) {
            throw "Erro ao integrar os dados complementares: " + result;
        } else {
            log.info("### SUCESSO! DADOS COMPLEMENTARES INTEGRADOS NA CHAPA " + CHAPA + " E PESSOA " + CODPESSOA);
        }

    } catch (e) {
        log.error("### ERRO FATAL NA INTEGRAÇÃO RM (Task 139): " + e);
        throw e;
    }
}

function servicetask138(attempt, message) {
    log.info("### Admissão SOAP RM (V_INTEGRADA_FINAL) - INICIO ###");

    try {
        // =========================================================================
        // 1. FUNÇÕES AUXILIARES DE FORMATAÇÃO E LEITURA (ROBUSTAS)
        // =========================================================================
        var getStr = function (name) {
            var v = hAPI.getCardValue(name);
            if (v == null || v == undefined) return "";
            return String(v).trim();
        };

        function tag(n, v) {
            if (v === null || v === undefined || String(v).trim() === "") return "";
            return "<" + n + ">" + escapeXML(v) + "</" + n + ">";
        }

        function tagInt(n, v) {
            var val = String(v || "").trim();
            if (val === "" || val === "null" || val === "undefined") return "<" + n + ">0</" + n + ">";
            return "<" + n + ">" + escapeXML(val) + "</" + n + ">";
        }

        function escapeXML(str) {
            return String(str || "").replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
        }

        function formatarDataRM(d) {
            if (!d || d == "") return "";
            var p = d.split("/");
            if (p.length == 3) {
                return p[2] + "-" + p[1] + "-" + p[0] + "T00:00:00";
            }
            return d;
        }

        function limparPontuacao(v) {
            return String(v || "").replace(/[^\w\s]/gi, '');
        }

        function formatarSalario(v) {
            if (!v || v === "") return "0,00";
            var limpo = String(v).replace("R$", "").trim();
            if (limpo.indexOf(",") > -1) {
                return limpo.replace(/\./g, "");
            } else {
                if (limpo.indexOf(".") > -1) {
                    return limpo.replace(/\./g, ",");
                } else {
                    return limpo + ",00";
                }
            }
        }

        function getUF(val) {
            if (!val || val === "") return "";
            var uf = String(val).trim().toUpperCase();
            if (uf === "UF" || uf === "SELECIONE") return "";
            var ufs = {
                "SÃO PAULO": "SP", "SAO PAULO": "SP", "MINAS GERAIS": "MG", "RIO DE JANEIRO": "RJ", "ESPÍRITO SANTO": "ES", "ESPIRITO SANTO": "ES",
                "BAHIA": "BA", "PARANÁ": "PR", "PARANA": "PR", "RIO GRANDE DO SUL": "RS", "SANTA CATARINA": "SC", "GOIÁS": "GO", "GOIAS": "GO",
                "DISTRITO FEDERAL": "DF", "MATO GROSSO": "MT", "MATO GROSSO DO SUL": "MS", "CEARÁ": "CE", "CEARA": "CE", "PERNAMBUCO": "PE",
                "PARÁ": "PA", "PARA": "PA", "AMAZONAS": "AM", "MARANHÃO": "MA", "MARANHAO": "MA", "PIAUÍ": "PI", "PIAUI": "PI",
                "RIO GRANDE DO NORTE": "RN", "PARAÍBA": "PB", "PARAIBA": "PB", "ALAGOAS": "AL", "SERGIPE": "SE", "TOCANTINS": "TO",
                "RONDÔNIA": "RO", "RONDONIA": "RO", "ACRE": "AC", "AMAPÁ": "AP", "AMAPA": "AP", "RORAIMA": "RR"
            };
            var sigla = ufs[uf] || uf.substring(0, 2);
            var validas = ["AC", "AL", "AP", "AM", "BA", "CE", "DF", "ES", "GO", "MA", "MT", "MS", "MG", "PA", "PB", "PR", "PE", "PI", "RJ", "RN", "RS", "RO", "RR", "SC", "SP", "SE", "TO", "EX"];
            if (validas.indexOf(sigla) === -1) return "";
            return sigla;
        }

        function getTipoRua(val) {
            if (!val || val === "") return "";
            var tipo = String(val).trim().toUpperCase();
            if (!isNaN(tipo)) return tipo;
            var map = { "RUA": "1", "AVENIDA": "6", "ALAMEDA": "4", "ESTRADA": "18", "RODOVIA": "34", "PRAÇA": "30", "PRACA": "30", "TRAVESSA": "39", "VIELA": "42" };
            return map[tipo] || "1";
        }

        function getTipoBairro(val) {
            if (!val || val === "") return "";
            var tipo = String(val).trim().toUpperCase();
            if (!isNaN(tipo)) return tipo;
            var map = { "BAIRRO": "1", "JARDIM": "11", "VILA": "18", "PARQUE": "14", "RESIDENCIAL": "15", "DISTRITO": "6", "SITIO": "16", "SÍTIO": "16" };
            return map[tipo] || "1";
        }

        function getEstadoCivilRM(val) {
            if (!val || val === "") return "S";
            var tipo = String(val).trim().toUpperCase();
            if (tipo.length === 1) return tipo;
            var map = { "SOLTEIRO": "S", "SOLTEIRA": "S", "CASADO": "C", "CASADA": "C", "DIVORCIADO": "D", "DIVORCIADA": "D", "VIÚVO": "V", "VIUVO": "V", "VIÚVA": "V", "VIUVA": "V", "SEPARADO": "P", "SEPARADA": "P", "UNIÃO ESTÁVEL": "E", "UNIAO ESTAVEL": "E", "COMPANHEIRO": "E", "DESQUITADO": "D", "OUTROS": "O" };
            return map[tipo] || "S";
        }

        function getGrauParentesco(val) {
            if (!val || val === "") return "";
            var tipo = String(val).trim().toUpperCase();
            if (tipo.indexOf("-") > -1) {
                var cod = tipo.split("-")[0].trim();
                if (cod.length === 1) return cod;
            }
            if (tipo.length === 1) return tipo;
            var map = { "FILHO(A) SEM DEFICIÊNCIA": "1", "FILHO": "1", "FILHA": "1", "FILHO(A)": "1", "FILHO(A) COM DEFICIÊNCIA": "3", "CÔNJUGE": "5", "CONJUGE": "5", "ESPOSA": "5", "MARIDO": "5", "PAI": "6", "MÃE": "7", "MAE": "7", "SOGRO(A)": "8", "SOGRO": "8", "SOGRA": "8", "OUTROS": "9" };
            return map[tipo] || "9";
        }

        function getGrauInstrucaoRM(val) {
            if (!val || val === "") return "7"; // Fallback padrão: 7 - Ensino Médio Completo

            var tipo = String(val).trim().toUpperCase();

            // Se já vier o código limpo do Fluig com 1 caractere (ex: "6", "9", "A", "B"), retorna direto
            if (tipo.length === 1) {
                return tipo;
            }

            // Mapeamento exato com base na tabela do RM
            var map = {
                "ANALFABETO": "1",
                "ATÉ O 5º ANO INCOMPLETO DO ENSINO FUNDAMENTAL": "2",
                "5º ANO COMPLETO DO ENSINO FUNDAMENTAL": "3",
                "DO 6º AO 9º ANO DO ENSINO FUNDAMENTAL": "4",
                "ENSINO FUNDAMENTAL COMPLETO": "5",
                "ENSINO MÉDIO INCOMPLETO": "6",
                "ENSINO MÉDIO COMPLETO": "7",
                "EDUCAÇÃO SUPERIOR INCOMPLETO": "8",
                "EDUCAÇÃO SUPERIOR COMPLETO": "9",
                "PÓS GRAD. INCOMPLETO": "A",
                "PÓS GRAD. COMPLETO": "B",
                "MESTRADO INCOMPLETO": "C",
                "MESTRADO COMPLETO": "D",
                "DOUTORADO INCOMPLETO": "E",
                "DOUTORADO COMPLETO": "F",
                "PÓS DOUT.INCOMPLETO": "G",
                "PÓS DOUT.COMPLETO": "H"
            };

            // Retorna o código mapeado ou, se não encontrar, manda "7" (Ensino Médio Completo)
            return map[tipo] || "7";
        }

        // =========================================================================
        // 2. CONFIGURAÇÕES DO WEBSERVICE 
        // =========================================================================
        var dsConfig = DatasetFactory.getDataset("Form_Configuracoes_Admissao", null, [
            DatasetFactory.createConstraint("metadata#active", "true", "true", ConstraintType.MUST)
        ], null);

        if (!dsConfig || dsConfig.rowsCount === 0) throw "ERRO FATAL: Configurações não encontradas.";

        var NOME_SERVICO_FLUIG = "WSDATASERVER";
        var RM_USER = dsConfig.getValue(0, "RM_USER");
        var RM_PASS = dsConfig.getValue(0, "RM_PASS");
        var ENDPOINT_URL = dsConfig.getValue(0, "RM_ENDPOINT_WS");

        var COLIGADA = getStr("FUN_EMPRESA");
        if (!COLIGADA || COLIGADA === "") throw "ERRO FATAL: A Coligada não foi informada.";
        var RM_CONTEXTO = "CODCOLIGADA=" + COLIGADA + ";CODSISTEMA=P;CODUSUARIO=" + RM_USER;

        // =========================================================================
        // 3. LÓGICA DE GERAÇÃO DE CHAPA (SEGURA)
        // =========================================================================
        var chapa = getStr("TxtChapa") || getStr("FUN_CHAPA");
        if (chapa == null || chapa == "" || chapa == "0000000") {
            try {
                var c1 = DatasetFactory.createConstraint("CODCOLIGADA", COLIGADA, COLIGADA, ConstraintType.MUST);
                var dsUltimaChapa = DatasetFactory.getDataset("ds_busca_ultima_chapa_rm", new Array(), new Array(c1), new Array());

                var numLinhas = (dsUltimaChapa != null && dsUltimaChapa.rowsCount !== undefined) ? dsUltimaChapa.rowsCount :
                    (dsUltimaChapa != null && dsUltimaChapa.values !== undefined) ? dsUltimaChapa.values.length : 0;

                if (numLinhas > 0) {
                    var ultimaChapaRaw = (typeof dsUltimaChapa.getValue === "function") ? dsUltimaChapa.getValue(0, "ULTIMA_CHAPA_CADASTRADA") : dsUltimaChapa.values[0]["ULTIMA_CHAPA_CADASTRADA"];
                    var tamanhoChapaRaw = (typeof dsUltimaChapa.getValue === "function") ? dsUltimaChapa.getValue(0, "TAMCHAPA") : dsUltimaChapa.values[0]["TAMCHAPA"];

                    var ultimaChapaStr = String(ultimaChapaRaw || "");
                    var tamanhoChapa = parseInt(String(tamanhoChapaRaw || "5"), 10);

                    if (ultimaChapaStr && ultimaChapaStr.indexOf("ERRO") === -1) {
                        var novaChapa = (parseInt(ultimaChapaStr, 10) + 1).toString();
                        while (novaChapa.length < tamanhoChapa) novaChapa = "0" + novaChapa;
                        chapa = novaChapa;
                    } else throw "Falha interna RM: " + ultimaChapaStr;
                }
            } catch (errChapa) { throw "ERRO AO CALCULAR A PRÓXIMA CHAPA: " + errChapa; }
        }

        // =========================================================================
        // 4. EXTRAÇÃO DOS DADOS (COM BLINDAGEM DE STRING E SPLIT)
        // =========================================================================
        var codPessoa = getStr("FUN_CODPESSOA");
        if (codPessoa === "0" || codPessoa.toUpperCase() === "NULL" || codPessoa.toUpperCase() === "UNDEFINED") codPessoa = "";

        var cpf = limparPontuacao(getStr("cpfcnpj"));
        var dtNasc = formatarDataRM(getStr("dtDataNascColaborador"));

        // Tratamento robusto Raça/Cor
        var racaCorRaw = getStr("CORRACA").toUpperCase();
        var racaCor = "";
        if (racaCorRaw === "0" || racaCorRaw.indexOf("INDIGENA") > -1) racaCor = "0";
        else if (racaCorRaw === "2" || racaCorRaw === "1" || racaCorRaw.indexOf("BRANCA") > -1) racaCor = "2";
        else if (racaCorRaw === "4" || racaCorRaw.indexOf("PRETA") > -1 || racaCorRaw.indexOf("NEGRA") > -1) racaCor = "4";
        else if (racaCorRaw === "6" || racaCorRaw.indexOf("AMARELA") > -1) racaCor = "6";
        else if (racaCorRaw === "8" || racaCorRaw.indexOf("PARDA") > -1) racaCor = "8";
        else if (racaCorRaw === "9" || racaCorRaw.indexOf("NÃO INFORMADO") > -1) racaCor = "9";
        else racaCor = "10";

        var grauInstrucao = getGrauInstrucaoRM(getStr("txtEscolaridade"));
        var estadoEnd = getUF(getStr("txtEstado"));
        var pais = getStr("txtPAIS");
        var dtAdmissaoXML = formatarDataRM(getStr("FUN_ADMISSAO"));
        if (!dtAdmissaoXML) throw "ERRO: Data de Admissão obrigatória não preenchida.";

        var salario = formatarSalario(getStr("FUN_VLRSALARIO"));
        var horasMensaisNum = parseFloat(getStr("cpQtdHorasMes") || getStr("FUN_HRMENSAIS") || "220");
        var usaSalComposto = getStr("cpUsaSalarioComposto") === "Sim" ? "1" : "0";

        // Funções genéricas de limpeza de IDs (pegando só o que vem antes do traço)
        var cleanId = function (val) { return val && val.indexOf("-") > -1 ? val.split("-")[0].trim() : val; };

        var codCCusto = cleanId(getStr("FUN_CC") || getStr("FUN_CCIDDESC"));
        var catESocial = cleanId(getStr("FUN_CATESOCIAL") || getStr("FUN_CATESOCIAL_IDDESC_AD"));
        var codSindicato = cleanId(getStr("cod_sindicato"));
        var seqTurno = cleanId(getStr("FUN_SEQTURN_IDDESC_AD") || getStr("FUN_SEQTURN"));
        var motivoAdmissao = cleanId(getStr("zoom_motivoAdmissao")) || "01";
        var codHorario = cleanId(getStr("FUN_CODTURN") || getStr("FUN_IDDESCTURN")) || "0001";
        if (codHorario.toUpperCase() === "CLT") codHorario = "0001";
        if (codHorario && codHorario.toUpperCase() === "CLT") codHorario = "0001";
        var codSecao = cleanId(getStr("FUN_SECAO") || getStr("FUN_SECAO_IDDESC_AD"));
        var codFuncao = cleanId(getStr("FUN_FUNCAO") || getStr("FUN_IDDESCFUN"));
        var tipoAdmissao = cleanId(getStr("FUN_TPADMISSAO_IDDESC_AD") || getStr("FUN_TPADMISSAO")) || "N";
        var codTipoFunc = getStr("codTipoFuncionario") || "N";
        var codCategoria = cleanId(getStr("FUN_CATSEFIP_IDDESC"));
        var tipoRegimeTrab = cleanId(getStr("cpRegimeTrabalhista"));
        var tipoRegimePrev = cleanId(getStr("cpRegimePrevidenciario") || getStr("FUN_TPREGIMEPREV")) || "1";
        if (tipoRegimePrev.length > 1) tipoRegimePrev = tipoRegimePrev.substring(0, 1);

        var contribSindical = cleanId(getStr("FUN_PGCTSIN_IDDESC_AD"));
        var integrContabil = cleanId(getStr("FUN_INTEGRCONTABIL_IDDESC"));
        var integrGerencial = cleanId(getStr("FUN_INTEGRGERENCIAL_IDDESC"));
        var indicativoAdmissao = cleanId(getStr("FUN_INDADMISSAO"));

        // =========================================================================
        // 5. MONTAGEM DO XML DO RM (COM OMISSÃO AUTOMÁTICA DE TAGS VAZIAS)
        // =========================================================================
        var xmlFunc = "<FopFunc>\n  <PFunc>\n";

        xmlFunc += tag("CODCOLIGADA", COLIGADA);
        xmlFunc += tag("CODFILIAL", getStr("FUN_FILIAL") || "1");
        xmlFunc += tag("CHAPA", (chapa == null || chapa == "") ? "-1" : chapa);

        if (codPessoa !== "") {
            xmlFunc += tag("CODPESSOA", codPessoa);
            xmlFunc += tag("CODIGO", codPessoa);
        }

        xmlFunc += tag("CODSITUACAO", "A");
        xmlFunc += tag("CODTIPO", codTipoFunc);
        if (tipoAdmissao) xmlFunc += tag("TIPOADMISSAO", tipoAdmissao);
        xmlFunc += tag("MOTIVOADMISSAO", motivoAdmissao);
        xmlFunc += tag("CODRECEBIMENTO", getStr("FUN_TIPOPGTO_IDDESC_AD").substring(0, 1).toUpperCase());
        if (codCategoria) xmlFunc += tag("CODCATEGORIA", codCategoria);
        xmlFunc += tag("SALARIO", salario);
        xmlFunc += tag("DATAADMISSAO", dtAdmissaoXML);
        xmlFunc += tag("DTBASE", dtAdmissaoXML);
        xmlFunc += tag("DTMUDANCASALARIO", dtAdmissaoXML);
        xmlFunc += tag("MOTMUDANCASALARIO", cleanId(getStr("zoom_motivoMudancaSalario")) || "01");
        xmlFunc += tag("DTMUDANCAFUNCAO", dtAdmissaoXML);
        xmlFunc += tag("MOTMUDANCAFUNCAO", cleanId(getStr("zoom_motivoMudancaFuncao")) || "01");
        xmlFunc += tag("DTMUDANCASECAO", dtAdmissaoXML);
        xmlFunc += tag("MOTMUDANCASECAO", cleanId(getStr("zoom_motivoMudancaSecao")) || "01");
        xmlFunc += tag("DTMUDANCAHORARIO", dtAdmissaoXML);
        xmlFunc += tag("HSTSIT_DATAMUDANCA", dtAdmissaoXML);
        xmlFunc += tag("HSTSIT_MOTIVO", cleanId(getStr("zoom_motivoMudancaSituacao")) || "01");
        
        // O RM exige a data de SEFIP na inclusão para todos, não podemos bloquear
        xmlFunc += tag("HSTSEFIP_DTMUDANCA", dtAdmissaoXML);
        
        // MANTÉM A PROTEÇÃO APENAS NO SINDICATO (Que era o erro original)
        if (codSindicato && codSindicato !== "") {
            xmlFunc += tag("DTMUDANCACONTRIBSINDICAL", dtAdmissaoXML);
        }

        // =========================================================================
        // REGRAS DE CONTRATO COM PRAZO / EXPERIÊNCIA
        // =========================================================================
        var tipoContratoPrazo = getStr("cpContratoPrazo");
        var dtFimContrato = formatarDataRM(getStr("cpTerminoContrato"));
        var assecuratoria = getStr("cpClausulaAssecuratoria") === "sim" ? "1" : "0";

        if (tipoContratoPrazo === "determinado" || tipoContratoPrazo === "experiencia") {
            // Marca a Flag de Contrato com Prazo como Sim (1)
            xmlFunc += tagInt("TEMPRAZOCONTR", "1");

            // Envia a Data Final e a Cláusula
            if (dtFimContrato) xmlFunc += tag("FIMPRAZOCONTR", dtFimContrato);
            xmlFunc += tagInt("TEMCLAUASSEG", assecuratoria);

            // Define o Tipo de Contrato no RM (Geralmente 2 = Experiência, 1 = Prazo Determinado/Lei 9601)
            var codTipoPrazo = (tipoContratoPrazo === "experiencia") ? "2" : "1";
            xmlFunc += tag("TIPOCONTRATOPRAZO", codTipoPrazo);

        } else {
            // Se for Indeterminado ou vazio, a Flag fica Não (0)
            xmlFunc += tagInt("TEMPRAZOCONTR", "0");
        }

        xmlFunc += tag("CODHORARIO", codHorario);
        xmlFunc += tag("JORNADAMENSAL", parseInt(horasMensaisNum * 60));
        xmlFunc += tag("Jornada_Mensal", horasMensaisNum + ":00");
        xmlFunc += tag("INDINICIOHOR", getStr("cpIndiceInicioHorario") || seqTurno);
        xmlFunc += tag("TIPOREGIMEJORNADA", getStr("FUN_TPJORNADA") || "1");
        xmlFunc += tag("TPREGIMEPREV", tipoRegimePrev);
        if (tipoRegimeTrab) xmlFunc += tag("TIPOREGIMETRABALHISTA", tipoRegimeTrab);
        xmlFunc += tagInt("USASALCOMPOSTO", usaSalComposto);

        // O SEGREDO ESTÁ AQUI: Se a variável estiver vazia, o IF pula e a tag não é enviada! (Adeus erro de FK)
        if (codSecao) xmlFunc += tag("CODSECAO", codSecao);
        if (codCCusto) xmlFunc += tag("CODCCUSTO", codCCusto);
        if (catESocial) xmlFunc += tag("CODCATEGORIAESOCIAL", catESocial);
        if (codFuncao) xmlFunc += tag("CODFUNCAO", codFuncao);
        if (codSindicato) xmlFunc += tag("CODSINDICATO", codSindicato);

        var sindicatoFiliacao = cleanId(getStr("FUN_CODDESCSINDICATOFILIACAO"));
        if (sindicatoFiliacao) xmlFunc += tag("CODSINDICATOFILIACAO", sindicatoFiliacao);

        var vinculoEmpreg = cleanId(getStr("FUN_VINCEMPREG_IDDESC_AD") || getStr("FUN_VINCEMPREG"));
        if (vinculoEmpreg) xmlFunc += tag("VINCULORAIS", vinculoEmpreg);

        xmlFunc += tag("SITUACAORAIS", getStr("cpSituacaoRais") || "1");
        xmlFunc += tag("SITUACAOFGTS", getStr("FUN_ALTFGTS"));
        xmlFunc += tag("DTSALDOFGTS", formatarDataRM(getStr("cpDataUltimoSaldoFGTS")));
        xmlFunc += tag("ESOCIALNATATIVIDADE", getStr("FUN_NATATIV"));

        if (indicativoAdmissao && indicativoAdmissao !== "S" && indicativoAdmissao !== "N") xmlFunc += tag("INDADMISSAO", indicativoAdmissao);

        xmlFunc += tag("SITUACAOINSS", getStr("FUN_INSS"));
        xmlFunc += tag("SITUACAOIRRF", getStr("FUN_IRRF"));

        if (contribSindical && contribSindical !== "S" && contribSindical !== "N") xmlFunc += tag("CONTRIBSINDICAL", contribSindical);
        // if (integrContabil && integrContabil !== "S" && integrContabil !== "N") xmlFunc += tag("INTEGRCONTABIL", integrContabil);
        //if (integrGerencial && integrGerencial !== "S" && integrGerencial !== "N") xmlFunc += tag("INTEGRGERENCIAL", integrGerencial);

        var codOcorrencia = cleanId(getStr("FUN_CODOCORRENCIA_IDDESC"));
        if (codOcorrencia) xmlFunc += tag("CODOCORRENCIA", codOcorrencia);

        // var codEquipe = getStr("cpCodigoEquipe");
        // if (codEquipe) xmlFunc += tag("CODEQUIPE", codEquipe);

        var codQuiosque = cleanId(getStr("FUN_CODQUIOSQUE_IDDESC"));
        if (codQuiosque) xmlFunc += tag("CODGRPQUIOSQUE", codQuiosque);

        xmlFunc += tagInt("USAVALETRANSP", getStr("ValeTransp") === "1" ? "1" : "0");
        xmlFunc += tagInt("TEMPOPARCIAL", getStr("FUN_CONTRATOPARCIAL") || "0");

        // Dados Pessoais
        xmlFunc += tag("NOME", getStr("txtNomeColaborador"));
        xmlFunc += tag("NOMESOCIAL", getStr("txtNomeSocial"));
        xmlFunc += tag("NOMEMAE", getStr("cand_mae_nome_") || getStr("txtNomDepen2"));
        xmlFunc += tag("NOMEPAI", getStr("cand_pai_nome_") || getStr("txtNomDepen3"));
        xmlFunc += tag("CPF", cpf);
        xmlFunc += tag("DTNASCIMENTO", dtNasc);
        xmlFunc += tag("SEXO", getStr("txtSexo"));
        xmlFunc += tag("ESTADOCIVIL", getEstadoCivilRM(getStr("txtEstadoCivil")));
        xmlFunc += tag("CORRACA", racaCor);
        xmlFunc += tag("GRAUINSTRUCAO", grauInstrucao);
        xmlFunc += tag("NACIONALIDADE", getStr("NACIONALIDADECod"));
        xmlFunc += tag("NATURALIDADE", getStr("txtNaturalidade"));
        xmlFunc += tag("CODNATURALIDADE", getStr("txtNaturalidadeCod"));
        xmlFunc += tag("ESTADONATAL", getUF(getStr("ESTADO")));

        var tpSanguineo = cleanId(getStr("TipoSanguineo"));
        if (tpSanguineo) xmlFunc += tag("TIPOSANG", tpSanguineo);

        // Endereço
        xmlFunc += tag("CEP", limparPontuacao(getStr("txtCEP")));
        xmlFunc += tag("CODTIPORUA", getTipoRua(getStr("_txtNOMETIPORUA") || getStr("txtNOMETIPORUA")));
        xmlFunc += tag("RUA", getStr("txtRUA"));
        xmlFunc += tag("NUMERO", getStr("txtNUMERO"));
        xmlFunc += tag("COMPLEMENTO", getStr("txtCOMPLEMENTO"));
        xmlFunc += tag("CODTIPOBAIRRO", getTipoBairro(getStr("txtNOMETIPOBAIRRO") || getStr("_txtNOMETIPOBAIRRO")));
        xmlFunc += tag("BAIRRO", getStr("txtBAIRRO"));
        xmlFunc += tag("CIDADE", getStr("txtNOMEMUNICIPIO"));
        var codMunicipio = getStr("txtCODMUNICIPIO");
        if (codMunicipio) xmlFunc += tag("CODMUNICIPIO", codMunicipio);
        xmlFunc += tag("ESTADO", getUF(getStr("txtNOMECODETD")));
        xmlFunc += tag("PAIS", pais);


        // Contato e Docs
        xmlFunc += tag("TELEFONE1", limparPontuacao(getStr("txtTELEFONE")));
        xmlFunc += tag("TELEFONE2", limparPontuacao(getStr("txtCELULAR")));
        xmlFunc += tag("EMAIL", getStr("txtEmail"));
        xmlFunc += tag("EMAILPESSOAL", getStr("txtEmail"));

        xmlFunc += tagInt("NIT", "0");
        xmlFunc += tagInt("ANO1EMPREGO", getStr("PIS_Ano_Primeiro_Emp"));
        xmlFunc += tagInt("DEFICIENTEFISICO", getStr("DEFICIENTEFISICO"));
        xmlFunc += tagInt("DEFICIENTEAUDITIVO", getStr("DEFICIENTEAUDITIVO"));
        xmlFunc += tagInt("DEFICIENTEFALA", getStr("DEFICIENTEFALA"));
        xmlFunc += tagInt("DEFICIENTEVISUAL", getStr("DEFICIENTEVISUAL"));
        xmlFunc += tagInt("DEFICIENTEMENTAL", getStr("DEFICIENTEMENTAL"));
        xmlFunc += tagInt("DEFICIENTEINTELECTUAL", getStr("DEFICIENTEINTELECTUAL"));

        xmlFunc += tag("CARTIDENTIDADE", getStr("TxtRg"));
        xmlFunc += tag("UFCARTIDENT", getUF(getStr("UFCARTIDENTIDADE")));
        xmlFunc += tag("ORGEMISSORIDENT", getStr("ORGAOCARTIDENTIDADE"));
        xmlFunc += tag("DTEMISSAOIDENT", formatarDataRM(getStr("DTEMISSAOIDENT")));

        xmlFunc += tag("TITULOELEITOR", getStr("TITULOELEITOR"));
        xmlFunc += tag("ZONATITELEITOR", getStr("ZONATITELEITOR"));
        xmlFunc += tag("SECAOTITELEITOR", getStr("SECAOTITELEITOR"));
        xmlFunc += tag("DTTITELEITOR", formatarDataRM(getStr("DTTITELEITOR")));
        xmlFunc += tag("ESTELEIT", getUF(getStr("UFTITULO")));

        xmlFunc += tag("CARTEIRATRAB", getStr("txtCartTrab"));
        xmlFunc += tag("SERIECARTTRAB", getStr("txtSerieCart"));
        xmlFunc += tag("UFCARTTRAB", getUF(getStr("UFCARTTRAB")));
        xmlFunc += tag("DTCARTTRAB", formatarDataRM(getStr("dtDataEmissaoCartTrab")));

        xmlFunc += tag("CARTMOTORISTA", getStr("CARTMOTORISTA"));
        xmlFunc += tag("TIPOCARTHABILIT", getStr("TIPOCARTHABILIT"));
        xmlFunc += tag("DTVENCHABILIT", formatarDataRM(getStr("DTVENCHABILIT")));
        xmlFunc += tag("ORGEMISSORCNH", getStr("ORGEMISSORCNH"));
        xmlFunc += tag("DTEMISSAOCNH", formatarDataRM(getStr("DTEMISSAOCNH")));
        xmlFunc += tag("DATAPRIMEIRACNH", formatarDataRM(getStr("DTEmPrimCNH")));
        xmlFunc += tag("UFCNH", getUF(getStr("CodUFCNH") || getStr("UFCNH")));

        xmlFunc += tag("CERTIFRESERV", getStr("CERTIFRESERV"));
        xmlFunc += tag("CATEGMILITAR", getStr("Reservista_Categoria"));
        xmlFunc += tag("CSM", getStr("Reservista_Circunscricao"));
        xmlFunc += tag("RM", getStr("Reservista_Regiao"));
        xmlFunc += tag("DTEXPCML", formatarDataRM(getStr("DtCERTIFRESERV")));
        xmlFunc += tag("EXPED", getStr("Reservista_Orgao"));
        xmlFunc += tag("SITMILITAR", getStr("SitMilitar"));

        xmlFunc += tag("NUMEROCARTAOSUS", limparPontuacao(getStr("Cartao_SUS")));

        xmlFunc += tag("PISPASEP", limparPontuacao(getStr("PIS")));

        xmlFunc += tag("NPASSAPORTE", getStr("Passaporte_Num"));
        xmlFunc += tag("DTEMISSPASSAPORTE", formatarDataRM(getStr("Passaporte_Emissao")));
        xmlFunc += tag("DTVALPASSAPORTE", formatarDataRM(getStr("Passaporte_Validade")));

        // Dados Bancários
        var codBanco = cleanId(getStr("txtCodBanPgto") || getStr("num_banco"));
        var codAgencia = cleanId(getStr("CodAgPagto") || getStr("num_agencia"));
        var contaCorrente = getStr("ContPagto");

        if (codBanco && contaCorrente) {
            xmlFunc += tag("CODBANCOPAGTO", codBanco);
            xmlFunc += tag("CODAGENCIAPAGTO", codAgencia);
            xmlFunc += tag("CONTAPAGAMENTO", contaCorrente);
            xmlFunc += tag("TPCONTABANCARIA", getStr("TipodeContPagto"));
            xmlFunc += tag("HSTBANCO_DTMUDANCA", dtAdmissaoXML);

            var bancoFGTS = cleanId(getStr("FUN_BANCOFGTS"));
            if (bancoFGTS) xmlFunc += tag("CODBANCOFGTS", bancoFGTS);

            var contaFGTS = getStr("cpContaFGTS");
            if (contaFGTS) xmlFunc += tag("CONTAFGTS", contaFGTS);

            var bancoPIS = cleanId(getStr("FUN_CODBANCOPIS"));
            if (bancoPIS) xmlFunc += tag("CODBANCOPIS", bancoPIS);

            var opBancaria = getStr("cpOperacaoBancaria");
            if (opBancaria) xmlFunc += tag("OPBANCARIA", opBancaria);
        }

        xmlFunc += tag("PERCENTADIANT", getStr("FUN_PADT"));
        xmlFunc += tag("AJUDACUSTO", formatarSalario(getStr("FUN_AJUDACUSTO")));
        var arredondamento = getStr("cpArredondamento") === "Sim" ? "1" : "0";
        xmlFunc += tag("ARREDONDAMENTO", arredondamento);


        xmlFunc += "  </PFunc>\n</FopFunc>";

        log.info("### XML DE INTEGRAÇÃO MONTADO (FUNCIONÁRIO): \n" + xmlFunc);

        // =========================================================================
        // 6. CONSUMO DO WEBSERVICE SOAP DO RM
        // =========================================================================
        var serviceProvider = ServiceManager.getService(NOME_SERVICO_FLUIG);
        var serviceLocator = serviceProvider.instantiate("com.totvs.WsDataServer");
        var authService = serviceLocator.getRMIwsDataServer();

        var client = authService;
        var bindingProvider = client;
        var requestContext = bindingProvider.getRequestContext();
        requestContext.put("javax.xml.ws.security.auth.username", RM_USER);
        requestContext.put("javax.xml.ws.security.auth.password", RM_PASS);

        try { requestContext.put("javax.xml.ws.service.endpoint.address", ENDPOINT_URL); } catch (e) { }

        var result = authService.saveRecord("FopFuncData", xmlFunc, RM_CONTEXTO);
        log.info("### RETORNO RM (FUNCIONÁRIO): " + result);

        // =========================================================================
        // TRATAMENTO DE AUTO-CORREÇÃO (PESSOA JÁ EXISTENTE)
        // =========================================================================
        if (result && result.indexOf("Foi encontrada uma pessoa com os mesmos dados") > -1) {
            var matchPessoa = result.match(/(\d+)\s+-/);
            if (matchPessoa && matchPessoa.length > 1) {
                var codPessoaExtraido = matchPessoa[1];
                log.info("### AUTO-CORREÇÃO: Injetando CODPESSOA: " + codPessoaExtraido);

                if (xmlFunc.indexOf("<CODPESSOA>") > -1) {
                    xmlFunc = xmlFunc.replace(/<CODPESSOA>.*?<\/CODPESSOA>/, "<CODPESSOA>" + codPessoaExtraido + "</CODPESSOA>\n    <CODIGO>" + codPessoaExtraido + "</CODIGO>");
                } else {
                    xmlFunc = xmlFunc.replace("</CHAPA>", "</CHAPA>\n    <CODPESSOA>" + codPessoaExtraido + "</CODPESSOA>\n    <CODIGO>" + codPessoaExtraido + "</CODIGO>");
                }

                result = authService.saveRecord("FopFuncData", xmlFunc, RM_CONTEXTO);
                hAPI.setCardValue("FUN_CODPESSOA", codPessoaExtraido);
            }
        }

        // =========================================================================
        // 7. VALIDAÇÃO DO RETORNO E CAPTURA DE CODPESSOA
        // =========================================================================
        var chapaFinal = "";
        if (result && result.indexOf("===") == -1) {
            chapaFinal = result.indexOf(";") > -1 ? result.split(";")[1] : result;
            hAPI.setCardValue("FUN_CHAPA", chapaFinal);
            hAPI.setCardValue("TxtChapa", chapaFinal);
            log.info("### SUCESSO! CHAPA GERADA: " + chapaFinal);

            // Captura o CodPessoa gerado pelo RM (Se for pessoa nova)
            try {
                if (!getStr("FUN_CODPESSOA")) {
                    var pkFuncionario = COLIGADA + ";" + chapaFinal;
                    var xmlRetornoRM = authService.readRecord("FopFuncData", pkFuncionario, RM_CONTEXTO);
                    var matchCodPessoaLeitura = String(xmlRetornoRM).match(/<CODPESSOA>(.*?)<\/CODPESSOA>/);

                    if (matchCodPessoaLeitura && matchCodPessoaLeitura.length > 1) {
                        hAPI.setCardValue("FUN_CODPESSOA", matchCodPessoaLeitura[1]);
                    }
                }
            } catch (errRead) { log.warn("### Falha ao ler CODPESSOA: " + errRead); }

        } else {
            throw "O RM rejeitou a admissão. Detalhes: " + result;
        }

        // =========================================================================
        // 8. INTEGRAÇÃO DOS DEPENDENTES (MANTIDA DO SEU PROJETO ATUAL)
        // =========================================================================
        try {
            var xmlDepend = "";
            var nroDepend = 0;
            var indexesDep = hAPI.getChildrenIndexes("tbItens");

            for (var i = 0; i < indexesDep.length; i++) {
                var idx = indexesDep[i];
                var nomeDep = getStr("txtNomDepen___" + idx);

                if (nomeDep !== "") {
                    nroDepend++;
                    var cpfDep = limparPontuacao(getStr("TxtCPFDep___" + idx));
                    var dtNascDep = formatarDataRM(getStr("cpDataNascimentoDep___" + idx));
                    var sexoDep = getStr("txtSexoDepen___" + idx);
                    var grauParentesco = getGrauParentesco(getStr("codParentesco___" + idx) || getStr("txtParentescoDepen___" + idx));

                    xmlDepend += "  <PFDepend>\n";
                    xmlDepend += tag("CODCOLIGADA", COLIGADA);
                    xmlDepend += tag("CHAPA", chapaFinal);
                    xmlDepend += tag("NRODEPEND", nroDepend.toString());
                    xmlDepend += tag("NOME", nomeDep);
                    if (cpfDep !== "") xmlDepend += tag("CPF", cpfDep);
                    if (dtNascDep !== "") xmlDepend += tag("DTNASCIMENTO", dtNascDep);
                    if (sexoDep !== "") xmlDepend += tag("SEXO", sexoDep.substring(0, 1).toUpperCase());
                    xmlDepend += tag("ESTADOCIVIL", getEstadoCivilRM(getStr("txtEstCivilCodDepen___" + idx) || getStr("txtEstadoCivilDepen___" + idx)));

                    xmlDepend += tag("NUMEROCARTAOSUS", limparPontuacao(getStr("TxtCartaoSusDep___" + idx)));
                    xmlDepend += tag("OBSERVACAO", getStr("TxtObsDep___" + idx));


                    xmlDepend += tag("INCIRRF", getStr("TxtIncIRRF___" + idx) || "0");
                    xmlDepend += tag("INCINSS", getStr("TxtIncINSS___" + idx) || "0");
                    xmlDepend += tag("INCASSISTMEDICA", getStr("TxtIncMedica___" + idx) || "0");
                    xmlDepend += tag("INCPENSAO", getStr("TxtIncPensao___" + idx) || "0");
                    if (grauParentesco !== "") xmlDepend += tag("GRAUPARENTESCO", grauParentesco);

                    xmlDepend += tag("PERCENTUAL", "0.00");
                    xmlDepend += tag("BRUTO", "0");
                    xmlDepend += tag("UNIVERSITARIO", "0");
                    xmlDepend += tag("INCSALFAM", getStr("TxtIncSalFamilia___" + idx) || "0");

                    var cartorio = getStr("TxtCartorio___" + idx);
                    if (cartorio !== "") xmlDepend += tag("CARTORIO", cartorio);
                    var registro = getStr("TxtRegistro___" + idx);
                    if (registro !== "") xmlDepend += tag("NROREGISTRO", registro);
                    var livro = getStr("TxtLivro___" + idx);
                    if (livro !== "") xmlDepend += tag("NROLIVRO", livro);
                    var folha = getStr("TxtFolha___" + idx);
                    if (folha !== "") xmlDepend += tag("NROFOLHA", folha);

                    xmlDepend += "  </PFDepend>\n";
                }
            }

            if (xmlDepend !== "") {
                var xmlDependFull = "<FopDepend>\n" + xmlDepend + "</FopDepend>";
                var resultDep = authService.saveRecord("FopDependData", xmlDependFull, RM_CONTEXTO);
                if (resultDep && resultDep.indexOf("===") != -1) throw "Erro dependentes: " + resultDep;
            }
        } catch (errDep) { throw errDep; }

    } catch (e) {
        log.error("### ERRO FATAL NA INTEGRAÇÃO RM: " + e);
        throw e;
    }
}

var BSE_FIM_APROVADO = 74;

function beforeStateEntry(sequenceId) {
	var numSolicitacao = getValue("WKNumProces");
	log.info('>>> ADMISSAO (beforeStateEntry): Processo ' + numSolicitacao + ' -> Indo para atividade: ' + sequenceId);

	// =========================================================================
	// 1. LÓGICA EXISTENTE: FIM APROVADO (INTEGRAÇÃO) - ATIVIDADE 74
	// =========================================================================
	if (sequenceId == BSE_FIM_APROVADO) {
		log.warn("AVISO: Datasets de integração (DS_FLUIG_0041 e ds_connector) não foram encontrados.");
		log.warn("AVISO: A integração com o RM e o envio de e-mail via TBC foram PULADOS para permitir o avanço do processo.");

		// montaXMLFunc();
		// montaXMLDependente();
	}

	// =========================================================================
	// 2. NOVA LÓGICA: ENVIO DE CORREÇÃO PARA O CANDIDATO - ATIVIDADE 150
	// =========================================================================
	// ATIVIDADE 150: Preparação de dados para a Correção (Entrada)
	if (sequenceId == 150) {
		log.info(">>> ADMISSAO (beforeStateEntry): Preparando dados para correção. Destino: 150");

		try {
			// Recupera o parecer digitado pelo RH na atividade anterior
			var parecerRH = hAPI.getCardValue("cpParecerAprovaAdmissao");

			// GRAVA NO CAMPO DE HISTÓRICO (Fundamental para a Widget Pública ler)
			hAPI.setCardValue("txtParecerHistoricoRH", parecerRH);

			// Limpa a resposta anterior do candidato
			hAPI.setCardValue("txtRespostaCorrecaoCandidato", "");

			log.info(">>> ADMISSAO: Dados de histórico gravados para a solicitação " + numSolicitacao);

		} catch (e) {
			log.error(">>> ADMISSAO: Erro ao gravar histórico no beforeStateEntry: " + e);
		}
	}

}





function montaXMLFunc() {
	// Função mantida no código para uso futuro, mas não será executada agora.
	log.info("Iniciando estrutura de montaXMLFunc (Inativa)...");

	log.info("Iniciando montaXMLFunc...");
	var CONNECT = DatasetFactory.getDataset("ds_connector", null, null, null);
	var USUARIO = CONNECT.getValue(0, "INTEGRADOR");
	var SENHA = CONNECT.getValue(0, "SENHA");

	log.info("Recuperou usuario e senha do ds_connector...");

	var formatoInput = new java.text.SimpleDateFormat("dd/MM/yyyy");
	var formatoOutput = new java.text.SimpleDateFormat("yyyy-MM-dd'T'00:00:00");

	var DatAdm = formatoInput.parse(hAPI.getCardValue("txtAdmissao"));
	DTAdmissao = formatoOutput.format(DatAdm);

	//DATA DE NASCIMENTO
	var Nasc = hAPI.getCardValue("dtDataNascColaborador");
	if (Nasc != "") {

		var DataNascimento = formatoInput.parse(hAPI.getCardValue("dtDataNascColaborador"));
		DTNASC = formatoOutput.format(DataNascimento);
	} if (Nasc == "") {
		DTNASC = "";
	}
	log.info("#### DTNASC: " + DTNASC);

	// DATE DE EMISSAO DA IDENTIDADE
	var dtEmRG = hAPI.getCardValue("DTEMISSAOIDENT");
	if (dtEmRG != "") {

		var DataRG = formatoInput.parse(hAPI.getCardValue("DTEMISSAOIDENT"));
		DTRG = formatoOutput.format(DataRG);
	} if (dtEmRG == "") {
		DTRG = "";
	}
	log.info("#### DTRG: " + DTRG);

	// DATA DE TITULO DE ELEITOR
	var DtTitu = hAPI.getCardValue("DTTITELEITOR");
	if (DtTitu != "") {

		var DataTitu = formatoInput.parse(hAPI.getCardValue("DTTITELEITOR"));
		DataTitulo = formatoOutput.format(DataTitu);
	} if (DtTitu == "") {
		DataTitulo = "";
	}
	log.info("#### DTRG: " + DTRG);

	// DATA DE EMISSAO DO CTPS
	var EmCarttrabDt = hAPI.getCardValue("dtDataEmissaoCartTrab");
	if (EmCarttrabDt != "") {

		var dtDataEmissaoCartTrab = formatoInput.parse(hAPI.getCardValue("dtDataEmissaoCartTrab"));
		DTCTPS = formatoOutput.format(dtDataEmissaoCartTrab);
	} if (EmCarttrabDt == "") {
		DTCTPS = "";
	}
	log.info("#### DTCTPS: " + DTCTPS);

	// DATA DE VENCIMENTO DA CNH
	var dtVencCNH = hAPI.getCardValue("DTVENCHABILIT");
	if (dtVencCNH != "") {

		var DTVENCHABILIT = formatoInput.parse(hAPI.getCardValue("DTVENCHABILIT"));
		DTCNH = formatoOutput.format(DTVENCHABILIT);
	} if (dtVencCNH == "") {
		DTCNH = "";
	}
	log.info("#### DTCNH: " + DTCNH);

	// DATA DE EMISSAO DA CNH
	var DtCNHEm = hAPI.getCardValue("DTEMISSAOCNH");
	if (DtCNHEm != "") {

		var DTEMISSAOCNH = formatoInput.parse(hAPI.getCardValue("DTEMISSAOCNH"));
		DTEMICNH = formatoOutput.format(DTEMISSAOCNH);
	} if (DtCNHEm == "") {
		DTEMICNH = "";
	}
	log.info("#### DTEMICNH: " + DTEMICNH);

	// DATA DE EMISSAO DO RIC
	var RICDt = hAPI.getCardValue("DtEmRIC");
	if (RICDt != "") {

		var DtEmRIC = formatoInput.parse(hAPI.getCardValue("DtEmRIC"));
		DtEMRIC = formatoOutput.format(DtEmRIC);
	} if (RICDt == "") {
		DtEMRIC = "";
	}
	log.info("#### DtEMRIC: " + DtEMRIC);

	// DATA DE EMISSAO DO RNE
	var RNEDt = hAPI.getCardValue("DTRNE");
	if (RNEDt != "") {

		var DTRNE = formatoInput.parse(hAPI.getCardValue("DTRNE"));
		DtRNE = formatoOutput.format(DTRNE);
	} if (RNEDt == "") {
		DtRNE = "";
	}
	log.info("#### DtRNE: " + DtRNE);

	// DATA DE CHEGADA NO BRASIL
