	// MOTIVOS
	xmlFunc += '	<MOTMUDANCASALARIO>01</MOTMUDANCASALARIO>	';
	xmlFunc += '	<MOTMUDANCASECAO>01</MOTMUDANCASECAO>	';
	xmlFunc += '	<MOTMUDANCAFUNCAO>1</MOTMUDANCAFUNCAO>	';
	xmlFunc += '	<HSTSIT_MOTIVO>01</HSTSIT_MOTIVO>	';

	xmlFunc += '	</PFunc>	';
